svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg         = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var tip    = document.getElementById('tip-layer');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  /* Ãƒâ€šÃ‚Â§2 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â isDark hoisted before all build and animation code */

  var pad  = 20;   // horizontal padding each side
  var bh   = 90;   // bubble body height
  var rx   = 12;   // corner radius
  var tail = 12;   // tail length
  var tw   = 10;   // half-width of tail opening

  function showTip(cx, barTopY, valStr, lblStr) {
    // 1. Set text content first
    tipVal.textContent = valStr;
    tipLbl.textContent = lblStr;

    // 2. Measure actual rendered widths with getBBox()
    var valW = tipVal.getBBox().width + pad * 2;
    var lblW = tipLbl.getBBox().width + pad * 2;
    var hw   = Math.max(valW, lblW, 60) / 2;  // half-width, min 60px total

    // 3. Clamp tx so bubble never exits card edges
    var tx = Math.max(hw + 8, Math.min(cx, 1100 - hw - 8));

    // 4. Bubble sits ABOVE the bar by default (tail points down toward bar).
    var ty = barTopY - tail - bh - 4;
    var flip = ty < 90;   // not enough headroom ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â flip below bar
    if (flip) ty = barTopY + tail + 4;

    // 5. Position group at (tx, ty) ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â local y=0 is top of bubble body
    tip.setAttribute('transform', 'translate(' + tx + ',' + ty + ')');

    // 6. Background rect
    tipBg.setAttribute('x', -hw);
    tipBg.setAttribute('y', 0);
    tipBg.setAttribute('width', hw * 2);
    tipBg.setAttribute('height', bh);
    tipBg.setAttribute('rx', rx);

    var bdrPath, tipPath;
    if (!flip) {
      // tail below ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â gap on bottom edge
      bdrPath =
        'M' + tw + ',' + bh +
        ' L' + (hw - rx) + ',' + bh +
        ' Q' + hw + ',' + bh + ' ' + hw + ',' + (bh - rx) +
        ' L' + hw + ',' + rx +
        ' Q' + hw + ',0 ' + (hw - rx) + ',0' +
        ' L' + -(hw - rx) + ',0' +
        ' Q' + (-hw) + ',0 ' + (-hw) + ',' + rx +
        ' L' + (-hw) + ',' + (bh - rx) +
        ' Q' + (-hw) + ',' + bh + ' ' + -(hw - rx) + ',' + bh +
        ' L' + (-tw) + ',' + bh;
      tipPath =
        'M' + tw + ',' + bh +
        ' L0,' + (bh + tail) +
        ' L' + (-tw) + ',' + bh;
    } else {
      // tail above ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â gap on top edge (flipped)
      bdrPath =
        'M' + (-tw) + ',0' +
        ' L' + -(hw - rx) + ',0' +
        ' Q' + (-hw) + ',0 ' + (-hw) + ',' + rx +
        ' L' + (-hw) + ',' + (bh - rx) +
        ' Q' + (-hw) + ',' + bh + ' ' + -(hw - rx) + ',' + bh +
        ' L' + (hw - rx) + ',' + bh +
        ' Q' + hw + ',' + bh + ' ' + hw + ',' + (bh - rx) +
        ' L' + hw + ',' + rx +
        ' Q' + hw + ',0 ' + (hw - rx) + ',0' +
        ' L' + tw + ',0';
      tipPath =
        'M' + (-tw) + ',0' +
        ' L0,' + (-tail) +
        ' L' + tw + ',0';
    }
    tipBdr.setAttribute('d', bdrPath);
    tipTip.setAttribute('d', tipPath);

    // 8. Text positions centred vertically in the bubble body
    tipVal.setAttribute('x', 0);
    tipVal.setAttribute('y', bh * 0.32);
    tipLbl.setAttribute('x', 0);
    tipLbl.setAttribute('y', bh * 0.70);

    tip.style.opacity = '1';
  }

  function hideTip() {
    tip.style.opacity = '';
  }

  var dataItemEls = Array.prototype.slice.call(document.querySelectorAll('.data-item'));
  dataItemEls.forEach(function(itemEl) {
    itemEl.addEventListener('mouseenter', function() {
      if (dataLayerEl) dataLayerEl.classList.add('hovering');
      dataItemEls.forEach(function(x) { x.classList.remove('active'); }); /* Ãƒâ€šÃ‚Â§4 clear stale */
      itemEl.classList.add('active');
      showTip(
        parseFloat(itemEl.getAttribute('data-cx')),
        parseFloat(itemEl.getAttribute('data-barty')),
        itemEl.getAttribute('data-val'),
        itemEl.getAttribute('data-lbl')
      );
    });
    itemEl.addEventListener('mouseleave', function() {
      itemEl.classList.remove('active');
      if (dataLayerEl) dataLayerEl.classList.remove('hovering');
      hideTip();
    });
  });

  /* Ãƒâ€šÃ‚Â§3/Ãƒâ€šÃ‚Â§4 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â gate hover on .ready after last bar animation completes */
  var BAR_COUNT   = 11;
  var BAR_STAGGER = Math.min(0.25, 1.0 / BAR_COUNT); /* adaptive: ~0.091s */
  var BAR_DUR     = 0.8;
  var lastBarDelay = (BAR_COUNT - 1) * BAR_STAGGER;
  setTimeout(function() { if (dataLayerEl) dataLayerEl.classList.add('ready'); },
    (lastBarDelay + BAR_DUR + 0.1) * 1000);

  /* Dark toggle */

  /* Print toggle */

  /* Inter-frame dark mode sync */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
